ps.pstext:
if !IsFeatureImplemented(FEAT_SME2) then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 8 << UInt(size);
let dn : integer = UInt(Zdn::'0');
let m : integer = UInt(Zm::'0');
let nreg : integer{} = 2;
let unsigned : boolean = TRUE;

if !IsFeatureImplemented(FEAT_SME2) then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 8 << UInt(size);
let dn : integer = UInt(Zdn::'00');
let m : integer = UInt(Zm::'00');
let nreg : integer{} = 4;
let unsigned : boolean = TRUE;

CheckStreamingSVEEnabled();
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV esize;
var results : array [[4]] of bits(VL);

for r = 0 to nreg-1 do
    let operand1 : bits(VL) = Z{}(dn+r);
    let operand2 : bits(VL) = Z{}(m+r);
    for e = 0 to elements-1 do
        let op1elt : bits(esize) = operand1[e*:esize];
        let element1 : integer = if unsigned then UInt(op1elt) else SInt(op1elt);
        let op2elt : bits(esize) = operand2[e*:esize];
        let element2 : integer = if unsigned then UInt(op2elt) else SInt(op2elt);
        let res : integer = Min(element1, element2);
        results[[r]][e*:esize] = res[esize-1:0];
    end;
end;

for r = 0 to nreg-1 do
    Z{VL}(dn+r) = results[[r]];
end;
